import sysfrom pathlib import Pathimport jsonimport joblibimport numpy as npimport pandas as pdimport torchfrom sklearn.linear_model import LogisticRegressionfrom sklearn.metrics import accuracy_score, f1_score, classification_report, confusion_matrixfrom tqdm import tqdmfrom transformers import AutoTokenizer, AutoModel# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import (    PROCESSED_DATA_DIR,    INTERIM_DATA_DIR,    BASELINE_MODELS_DIR,    REPORTS_DIR,    TABLE_DIR,)DATASET_TAG = "large_lite"EXPERIMENT_TAG = "finbert_v1"TEXT_COL = "full_text"LABEL_COL = "label_5d"MODEL_NAME = "ProsusAI/finbert"# long-document chunkingMAX_LENGTH = 512CHUNK_BODY_LEN = 510MAX_CHUNKS_PER_DOC = 12# chunk encoding batch sizeBATCH_SIZE = 8DEVICE = "cuda" if torch.cuda.is_available() else "cpu"def load_data():    train_df = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d_large_lite.parquet")    val_df = pd.read_parquet(PROCESSED_DATA_DIR / "validation_doc_5d_large_lite.parquet")    test_df = pd.read_parquet(PROCESSED_DATA_DIR / "test_doc_5d_large_lite.parquet")    return train_df, val_df, test_dfdef basic_data_check(df: pd.DataFrame, split_name: str):    print(f"\n--- {split_name.upper()} ---")    print("Shape:", df.shape)    print("Label distribution:")    print(df[LABEL_COL].value_counts(dropna=False).sort_index())    print(df[[TEXT_COL, LABEL_COL]].head(2))def load_finbert():    print(f"\nLoading tokenizer and model: {MODEL_NAME}")    tokenizer = AutoTokenizer.from_pretrained(MODEL_NAME)    model = AutoModel.from_pretrained(MODEL_NAME)    if tokenizer.pad_token_id is None:        tokenizer.pad_token = tokenizer.eos_token if tokenizer.eos_token is not None else tokenizer.unk_token    model.to(DEVICE)    model.eval()    return tokenizer, modeldef chunk_document(text: str, tokenizer):    """    Tokenize once without truncation, then split into chunks.    Each chunk receives special tokens later via prepare_for_model().    """    text = str(text)    token_ids = tokenizer.encode(text, add_special_tokens=False)    chunks = []    for i in range(0, len(token_ids), CHUNK_BODY_LEN):        if len(chunks) >= MAX_CHUNKS_PER_DOC:            break        chunk_ids = token_ids[i:i + CHUNK_BODY_LEN]        encoded = tokenizer.prepare_for_model(            chunk_ids,            add_special_tokens=True,            max_length=MAX_LENGTH,            truncation=True,            return_attention_mask=True,        )        chunks.append(encoded)    if len(chunks) == 0:        encoded = tokenizer(            "",            return_attention_mask=True,            truncation=True,            max_length=MAX_LENGTH,        )        chunks = [{            "input_ids": encoded["input_ids"],            "attention_mask": encoded["attention_mask"],        }]    return chunksdef pad_batch(chunk_batch, pad_token_id):    """    Pad one batch of chunks to the same length.    """    max_len = max(len(x["input_ids"]) for x in chunk_batch)    input_ids = []    attention_masks = []    for x in chunk_batch:        ids = x["input_ids"]        mask = x["attention_mask"]        pad_len = max_len - len(ids)        ids = ids + [pad_token_id] * pad_len        mask = mask + [0] * pad_len        input_ids.append(ids)        attention_masks.append(mask)    return (        torch.tensor(input_ids, dtype=torch.long, device=DEVICE),        torch.tensor(attention_masks, dtype=torch.long, device=DEVICE),    )def mean_pool(last_hidden_state, attention_mask):    """    Mean pooling over token embeddings, excluding padding.    """    mask = attention_mask.unsqueeze(-1).expand(last_hidden_state.size()).float()    masked_embeddings = last_hidden_state * mask    summed = masked_embeddings.sum(dim=1)    counts = mask.sum(dim=1).clamp(min=1e-9)    return summed / countsdef encode_documents(texts, tokenizer, model, split_name):    """    For each document:    - split into <= MAX_CHUNKS_PER_DOC chunks    - encode each chunk with FinBERT    - mean-pool tokens within each chunk    - average chunk embeddings to one document embedding    """    all_doc_embeddings = []    chunk_counts = []    print(f"\nEncoding {split_name} documents on {DEVICE} ...")    for text in tqdm(texts, desc=f"Encoding {split_name}"):        chunks = chunk_document(text, tokenizer)        chunk_counts.append(len(chunks))        chunk_embeddings = []        for i in range(0, len(chunks), BATCH_SIZE):            chunk_batch = chunks[i:i + BATCH_SIZE]            input_ids, attention_mask = pad_batch(chunk_batch, tokenizer.pad_token_id)            with torch.no_grad():                outputs = model(input_ids=input_ids, attention_mask=attention_mask)                pooled = mean_pool(outputs.last_hidden_state, attention_mask)            chunk_embeddings.append(pooled.cpu().numpy())        chunk_embeddings = np.vstack(chunk_embeddings).astype(np.float32)        doc_embedding = np.mean(chunk_embeddings, axis=0).astype(np.float32)        all_doc_embeddings.append(doc_embedding)    X = np.vstack(all_doc_embeddings).astype(np.float32)    return X, chunk_countsdef train_classifier(X_train, y_train, X_val, y_val):    candidates = [        {"C": 0.1},        {"C": 1.0},        {"C": 10.0},    ]    best_model = None    best_result = None    all_results = []    for i, cfg in enumerate(candidates, start=1):        print(f"\nTraining candidate {i}: {cfg}")        clf = LogisticRegression(            C=cfg["C"],            max_iter=3000,            random_state=42,        )        clf.fit(X_train, y_train)        val_pred = clf.predict(X_val)        acc = accuracy_score(y_val, val_pred)        f1 = f1_score(y_val, val_pred)        result = {            "candidate_id": i,            "C": cfg["C"],            "val_accuracy": acc,            "val_f1": f1,        }        all_results.append(result)        print(f"Validation Accuracy: {acc:.4f}")        print(f"Validation F1:       {f1:.4f}")        if best_result is None or f1 > best_result["val_f1"]:            best_result = result            best_model = clf    return best_model, best_result, pd.DataFrame(all_results)def evaluate_on_test(model, X_test, y_test):    test_pred = model.predict(X_test)    test_acc = accuracy_score(y_test, test_pred)    test_f1 = f1_score(y_test, test_pred)    cm = confusion_matrix(y_test, test_pred)    clf_report = classification_report(y_test, test_pred, output_dict=True)    print("\n=== TEST PERFORMANCE ===")    print(f"Test Accuracy: {test_acc:.4f}")    print(f"Test F1:       {test_f1:.4f}")    print("Confusion Matrix:")    print(cm)    return {        "test_accuracy": test_acc,        "test_f1": test_f1,        "confusion_matrix": cm.tolist(),        "classification_report": clf_report,    }def save_outputs(    clf,    best_result,    validation_results_df,    test_results,    X_train,    X_val,    X_test,    train_chunk_counts,    val_chunk_counts,    test_chunk_counts,):    BASELINE_MODELS_DIR.mkdir(parents=True, exist_ok=True)    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    TABLE_DIR.mkdir(parents=True, exist_ok=True)    INTERIM_DATA_DIR.mkdir(parents=True, exist_ok=True)    model_path = BASELINE_MODELS_DIR / f"finbert_embedding_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}.joblib"    report_path = REPORTS_DIR / f"finbert_embedding_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}_results.json"    val_table_path = TABLE_DIR / f"finbert_embedding_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}_validation_results.csv"    train_embed_path = INTERIM_DATA_DIR / f"train_doc_embedding_finbert_{DATASET_TAG}_{EXPERIMENT_TAG}.npy"    val_embed_path = INTERIM_DATA_DIR / f"validation_doc_embedding_finbert_{DATASET_TAG}_{EXPERIMENT_TAG}.npy"    test_embed_path = INTERIM_DATA_DIR / f"test_doc_embedding_finbert_{DATASET_TAG}_{EXPERIMENT_TAG}.npy"    np.save(train_embed_path, X_train)    np.save(val_embed_path, X_val)    np.save(test_embed_path, X_test)    joblib.dump(clf, model_path)    validation_results_df.to_csv(val_table_path, index=False)    payload = {        "dataset_tag": DATASET_TAG,        "experiment_tag": EXPERIMENT_TAG,        "model_name": MODEL_NAME,        "device": DEVICE,        "max_length": MAX_LENGTH,        "max_chunks_per_doc": MAX_CHUNKS_PER_DOC,        "best_validation_result": best_result,        "test_results": test_results,        "avg_train_chunks_per_doc": float(np.mean(train_chunk_counts)),        "avg_validation_chunks_per_doc": float(np.mean(val_chunk_counts)),        "avg_test_chunks_per_doc": float(np.mean(test_chunk_counts)),    }    with open(report_path, "w", encoding="utf-8") as f:        json.dump(payload, f, indent=2)    print("\nSaved outputs:")    print(model_path)    print(report_path)    print(val_table_path)    print(train_embed_path)    print(val_embed_path)    print(test_embed_path)def main():    print(f"Using device: {DEVICE}")    train_df, val_df, test_df = load_data()    basic_data_check(train_df, "train")    basic_data_check(val_df, "validation")    basic_data_check(test_df, "test")    tokenizer, model = load_finbert()    X_train, train_chunk_counts = encode_documents(        train_df[TEXT_COL].astype(str).tolist(), tokenizer, model, "train"    )    X_val, val_chunk_counts = encode_documents(        val_df[TEXT_COL].astype(str).tolist(), tokenizer, model, "validation"    )    X_test, test_chunk_counts = encode_documents(        test_df[TEXT_COL].astype(str).tolist(), tokenizer, model, "test"    )    y_train = train_df[LABEL_COL].astype(int).values    y_val = val_df[LABEL_COL].astype(int).values    y_test = test_df[LABEL_COL].astype(int).values    print(f"\nEmbedding shapes:")    print(f"Train:      {X_train.shape}")    print(f"Validation: {X_val.shape}")    print(f"Test:       {X_test.shape}")    print(f"\nAverage chunks per doc:")    print(f"Train:      {np.mean(train_chunk_counts):.2f}")    print(f"Validation: {np.mean(val_chunk_counts):.2f}")    print(f"Test:       {np.mean(test_chunk_counts):.2f}")    best_model, best_result, validation_results_df = train_classifier(        X_train, y_train, X_val, y_val    )    print("\nBest validation configuration:")    print(best_result)    test_results = evaluate_on_test(best_model, X_test, y_test)    save_outputs(        best_model,        best_result,        validation_results_df,        test_results,        X_train,        X_val,        X_test,        train_chunk_counts,        val_chunk_counts,        test_chunk_counts,    )    print("\nDone.")if __name__ == "__main__":    main()